void i2c_slave_core::thread_hdltv_gen() {
    const char* dump_tv = std::getenv("AP_WRITE_TV");
    if (!(dump_tv && string(dump_tv) == "on")) return;

    wait();

    mHdltvinHandle << "[ " << endl;
    mHdltvoutHandle << "[ " << endl;
    int ap_cycleNo = 0;
    while (1) {
        wait();
        const char* mComma = ap_cycleNo == 0 ? " " : ", " ;
        mHdltvinHandle << mComma << "{"  <<  " \"ap_rst\" :  \"" << ap_rst.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"ap_start\" :  \"" << ap_start.read() << "\" ";
        mHdltvoutHandle << mComma << "{"  <<  " \"ap_done\" :  \"" << ap_done.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"ap_idle\" :  \"" << ap_idle.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"ap_ready\" :  \"" << ap_ready.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"i2c_in\" :  \"" << i2c_in.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"i2c_sda_out_i\" :  \"" << i2c_sda_out_i.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"i2c_sda_out_o\" :  \"" << i2c_sda_out_o.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"i2c_sda_oe_i\" :  \"" << i2c_sda_oe_i.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"i2c_sda_oe_o\" :  \"" << i2c_sda_oe_o.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"dev_addr_in\" :  \"" << dev_addr_in.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"auto_inc_regad_in\" :  \"" << auto_inc_regad_in.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"mem_addr_i\" :  \"" << mem_addr_i.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"mem_addr_o\" :  \"" << mem_addr_o.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"mem_din\" :  \"" << mem_din.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"mem_dout_i\" :  \"" << mem_dout_i.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"mem_dout_o\" :  \"" << mem_dout_o.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"mem_wreq_i\" :  \"" << mem_wreq_i.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"mem_wreq_o\" :  \"" << mem_wreq_o.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"mem_wack\" :  \"" << mem_wack.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"mem_rreq_i\" :  \"" << mem_rreq_i.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"mem_rreq_o\" :  \"" << mem_rreq_o.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"mem_rack\" :  \"" << mem_rack.read() << "\" ";
        mHdltvinHandle << "}" << std::endl;
        mHdltvoutHandle << "}" << std::endl;
        ap_cycleNo++;
    }
}

